INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2358596','Гімн Воєнної розвідки України','Музика: Сергій Льовін Слова: Сергій Льовін. Виконує: Сергій Льовін','uk','ukraine_1991',NULL,NULL,'Книга Сергія Льовіна "Знайти себе": Вірші та пісні – Київ, 2012. – 250 с.','Пісню виконує гурт "Оберіг" (альбом: Воєнній розвідці України присвячується).','Оголошує день світанок,
Прокидаються Київ, Сміла...
Оксамитовий, добрий ранок
Розправляє країні крила.
Тільки пильний доби дослідник
Непомітно, відсутній наче,
Ратну службу несе розвідник -
Все почує і все побачить.

Приспів:
Він в бою, як митець у пошуку:
Розум перемагає силу.
Я з таким би пішов у розвідку, -
Про таких завжди говорили.
До останнього кроку-подиху
В серці - віра, в очах - відвага.
Ось такий прославляє розвідку,
Ось таких визнає звитяга.

Він і в небі, і під водою
У готовності до наказу.
Від часів пластунів-героїв
До сьогоднішнього спецназу.
Зігріває любов безмежна,
Десь чекає його родина.
Незрівнянна і незалежна,
Розквітай і міцній, Вкраїно!

Приспів','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2358596'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2358596','Гімн Воєнної розвідки України','Оголошує день світанок,
