INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2357952','На злітній смузі','Музика: Людмила Качало Слова: Людмила Качало','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує SINGLE SWEET.','У минулі дні нема вороття,
Переповнили серце спогади п''янкі,
Хай благословить Господь
На чужині твоє життя.
Залишилось все в темряві німій,
Відцвіла твоя юність, наче первоцвіт,
Біль розлук в твоїм серці,
А в твоїх руках - цілий світ...

Приспів:
Лід вогнів на злітній смузі,
А це не сніг - це сльози твоїх друзів...
Мрій тепло загоїть рани,
Ще мить - і твій літак у небі тане
В далекий край, в далекий край...

Пригадаєш дні, дні твого життя... -
Защемить не раз серце в дальній стороні
Бо не гріє так сонце,
Як на твоїй рідній землі...
Не потрібно всім море зайвих слів...
Пригадай не раз друзів і землю свою...
Бо не світять так зорі,
Як у твоїм ріднім краю...

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2357952'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2357952','На злітній смузі','У минулі дні нема вороття,
