INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2360818','У мене немає дому','Музика: Ірина Швайдак, Устим Похмурський Слова: Ірина Швайдак. Виконує: Один в каное','uk','ukraine_1991',NULL,NULL,'аудіозапис; Акорди (частково): https://youtu.be/M5CxFK26JqY',NULL,'Справа в тому,
Що в мене немає дому
І за правилом доброго тону,
Як за правилом доброго ременя,
Я згадаю з якого я племені,
Пригадаю з якого міста,
Я чекаю на своє Греммі,
В мене просто нема де сісти
Написати свою промову:
У мене немає дому... | (3)
Приспів:
А люди такі, люди такі всоте
За день в свої бетонні соти!
А де їм ше ховатись, сохнути,
Людям першого, другого сорту?..
А люди такі, люди такі сотнями
В тандемі зі своїми висотками
З третього, сьомого герцами-герцами
Сповнюють все сенсами-сенсами...
Справа в тому,
Що у мене немає дому
Тепер я ніколи й нічого нікому -
Ти перший з ким ділю свою колу
І більше... Але врешті, а втім,
Якби в мене був дім,
Я б лишила його на людей, на котів
Я б пошила усіх, я не люблю кутів!..
Приспів.
Люди такі... Ми люди такі...
Ми люди такі... Ми люди такі...
Люди такі... Ми люди...
Акорди: капо на 4 ладі
= оригінальна тональність
Вступ:   Am(add9)
Куплет:  Am(add9) Em F C Em
Am(add9)
Приспів: Am Em F C Em
Замість Am(add9) [01420x]
простіше можна Am.','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2360818'), datetime('now')),datetime('now'));
