INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2361063','Частівки','Слова: Любов Іванова','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Заробила вчора брагу,
Хай там буде про запас.
Мій Петро тамує спрагу -
Ходить в клуню кожен час.

А в куми моєї Тані
Редьки соток п''ять, мабуть.
Мужики з-під бару п''яні
Під закуску її рвуть.

Теща з зятем розсварились,
Не говорять певно з рік!
А дочка - не заступилась
Зять до другої утік!..

Самогонку молодиці
Продавали на розлив,
Бо в селі Гнилі Кислиці
Більш нема альтернатив.

На дієту сіла Дінка -
Чи то баба, чи мужик?..
Де колись була ширінка,
Стрінги моднії впритик...

Ущипнув гусак за ляжку,
Ну а я візьму граблі,
Запряжу його в упряжку
Хай катає по селі.

Як по місту, по Парижу
Вів Іван діваху рижу,
А батькам відправив вістку:
Мов, везу для вас невістку.

Мав піддати куражу
Мій миленький Міша
Роздягнулась і лежу
Тиждень, чи вже й більше!

А на березі вербичка,
Соловейко тьох та тьох!
Глянь, Петро, яка травичка,
Давай ляжемо удвох!

Запросила я Серьожку
До ставка спуститись вниз,
Будуть танці під гармошку,
А за танцями - стриптиз!

Коло річки, коло Бугу
Витинали гопака.
Мій Петро цілує другу
Я вже, бачте, не така...

Я - хороша господиня,
Тільки ось яка біда:
Уродилась одна диня
Решта поля - лобода!','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2361063'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2361063','Частівки','Заробила вчора брагу,
Хай там буде про запас.
Мій Петро тамує спрагу -
Ходить в клуню кожен час.

А в куми моєї Тані
Редьки соток п''ять, мабуть.
Мужики з-під бару п''яні
Під закуску її рвуть.

Теща з зятем розсварились,
Не говорять певно з рік!
А дочка - не заступилась
Зять до другої утік!..

Самогонку молодиці
Продавали на розлив,
Бо в селі Гнилі Кислиці
Більш нема альтернатив.

На дієту сіла Дінка -
Чи то баба, чи мужик?..
Де колись була ширінка,
Стрінги моднії впритик...

Ущипнув гусак за ляжку,
Ну а я візьму граблі,
Запряжу його в упряжку
Хай катає по селі.

Як по місту, по Парижу
Вів Іван діваху рижу,
А батькам відправив вістку:
Мов, везу для вас невістку.

Мав піддати куражу
Мій миленький Міша
Роздягнулась і лежу
Тиждень, чи вже й більше!

А на березі вербичка,
Соловейко тьох та тьох!
Глянь, Петро, яка травичка,
Давай ляжемо удвох!

Запросила я Серьожку
До ставка спуститись вниз,
Будуть танці під гармошку,
А за танцями - стриптиз!

Коло річки, коло Бугу
Витинали гопака.
Мій Петро цілує другу
Я вже, бачте, не така...

Я - хороша господиня,
Тільки ось яка біда:
Уродилась одна диня
Решта поля - лобода!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236212','Україно, любов моя','Музика: Ігор Шамо Слова: Дмитро Луценко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Як не любить тебе, Україно!
Ніжних світань і прозорих криниць,
Червоних зірниць і пісень солов''їних
В рідних шумливих гаях.

Приспів:
Моя Батьківщино,
Моя Україно,
Вкраїно, любов моя!

Ти простяглась за сині Карпати,
В буйних садах і в розмаї дібров.
Як вірну любов, як лагідну матір,
В серці ношу тебе я.

Приспів.

Ти розцвіла у блакитних барвінках,
В славі й добрі, як веселка ясна.
Співа далина про молодість дзвінко,
В радості й щасті сія.

Приспів.

Де б я не був, а кручі Славути,
Села й міста в подніпровім краю,
Як матір свою, я не можу забути,
Завжди люблю тебе я!

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236212'), datetime('now')),datetime('now'));
