INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2360653','Благословіння','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ось і виросли мої донечки,
Розцвіли, наче маків цвіт,
І кохання, неначе сонечко,
Свій гарячий несе привіт.
Відпускати їх серцю боляче
У далекі незнані світи...
То прийшла пора, мої донечки,
Тож летіть собі!.. Тож летіть!..

Приспів:
Вишневим цвітом розцвітуть сади
І зорі в небі радісно засяють,
Щоб на шляху не сталося біди,
Я на порозі Вас благословляю!

Хай засвітиться зірка ранняя
Ясним променем золотим,
Щоб щасливими, щоб коханими
Ви були у житті своїм!
Щоб сміялися ранки сонячно,
У цілунках коханих вуст,
Швидко виросли мої донечки,
Відпускати їх так боюсь...

Приспів. (2)

Я на порозі Вас благословляю!..','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2360653'), datetime('now')),datetime('now'));
