INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2360226','Гімн байкерів','Музика: Гурт НЕ лізь БО вб''є Слова: Андрій Рудик. Виконує: Гурт НЕ лізь БО вб''є','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'G5
Старт як каменепад, гуркіт і гул,
Це в дорогу рушає Загул,
G5
Іскри і дим спалених шин,
Брат за брата та всі як один!
Під ревіння своїх двигунів
Мчать дорогами вільних вітрів,
Розриваючи світлом пітьму
Очі нічних хижаків.

Приспів:
Загул братство із вільних людей,
Загул, зграя сталевих коней,
Загул, буря і грім підібрались,
В притул їде Загул.

G5
Шлях в наших серцях, блиском в очах,
Правдою в наших словах
G5
Вдень і в ночі в променях фар
Напрям вкаже небесний ліхтар.
Хай то Південь, Північ чи Схід
Мчить колона на байкерський зліт,
З центру і аж до зелених Карпат
Мчить мотобрат!

Приспів.','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2360226'), datetime('now')),datetime('now'));
