INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236073','Ой піду я в полонину','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні з Полонини(закарпатські народні пісні)-К.:видавництво"Дніпро",1973р.',NULL,'Ой піду я в полонину,
Ой піду я лугом,
Там мій милий чорнобривий
Оре новим плугом.

Ой піду я до милого,
Понесу му їсти,
То він мене поцілує,
Ще й попросить сісти

Ой мій милий чорнобривий
Наївся, напився
Та й на свою білявочку
Щиро надивися.','["pisni.org.ua", "cat:zakarpatski", "Закарпатські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236073'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236073','Ой піду я в полонину','Ой піду я в полонину,
