INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2362756','Пісня про Олесю','Музика: Ярослав Музика Слова: Валерій Терзі. Виконує: Віктор Гембара','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Пролітала лебідонька,
Сіла край могили,
Розказала тихо Лесі,
Як сумує милий...
Завітали також в гості
Голуби у парі,
Задивились на світлину
Лесину в емалі...

Приспів:
Молода вродлива пані
Сумно споглядає...
Чи не бачили дитини? -
В голубів питає...
Молода вродлива пані
Сумно споглядає...
Чи не бачили дитини? - |
В голубів питає...     | (2)

Підроста твоя дитина,
Вже не зна печалі,
А тебе стара матуся
Виглядає з далі...
Батько згорбився від горя,
Сліз не вистачає,
Де ти, сонце наше?.. Де ти?..
Чом тебе немає?..

Приспів.

Прилетіла і журавка
Із чужого краю,
Рідний степ, гаї, долини
Радо зустрічають!..
Ходить птаха сіроока,
Дивиться навколо,
А їй тут усе знайоме,
Миле все до болю!..

Приспів.

Як же ж так, Олесю люба,
Зіронько ти ясна,
Чом покинула так рано
Світ оцей прекрасний?
Але ми живем тобою,
Доню незабутня,
І у цьому полягає
Наша вічна сутність!..

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2362756'), datetime('now')),datetime('now'));
