INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2359096','А мати сина жде і виглядає в полі','Українська народна пісня. Виконує: Богдан Малик','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Зацвів дитинства сад
Барвінком і любистком,
Пішов на фронт солдат,
Упав під обеліском...

Приспів:
А мати сина жде         |
І виглядає в полі...    |
А син не йде, не йде,   |
Не прийде вже ніколи... | (2)

Із ним вона у снах
Збирає буйні квіти,
Син поряд, молодий,
Не з бронзи, не відлитий...

Приспів.

Летять, летять роки,
Тривожать сивиною,
Поліг навік солдат,
Похований війною...

Приспів','["pisni.org.ua", "cat:nostalgia", "cat:pro-ditey", "Пісні з ностальгічними мотивами", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2359096'), datetime('now')),datetime('now'));
