INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2362993','Ти повернись на Україну!','Музика: Ярослав Музика Слова: Олександр Лисенко. Виконує: Ярослав Музика','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У Римі вже цвітом буяють сади,
А в нас не розтанув ще сніг...
За щастям далеко поїхала ти -
І стримать тебе я не зміг...
У вічному місті, де давні руїни,
Щодня ти блукаєш сама,
Із смутком читаєш листи з України -
І в серці твоєму зима...

Приспів:
Я кличу і молю тебе:     |
Ти повернись на Україну, |
Де небо чисте й голубе   |
І чути мову солов''їну!   | (2)

Ти щастя шукаєш в далекій країні,
Де ліри дешеві дзвенять,
Та серцем лишилась на Україні -
Від сліз твої вії тремтять...
Я згадую очі, що кольору неба,
Сумую без тебе щодня...
Жорстокого щастя, повір, нам не треба,
Єдина, кохана моя!

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2362993'), datetime('now')),datetime('now'));
