INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236226','Козацькому роду нема переводу','Музика: Микола Балема Слова: Мирослав Воньо. Виконує: Володимир Гуменчук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Сяяли на сонці шаблі запорожців,
Як вони на конях гнали ворогів.
Козацькому роду нема переводу,
Лине його слава з далечі віків.

Приспів:

Гей, співай, козаки,
Про любов, про землю святу,
Про землю.
Славте, гей, козаки,
Волю золоту.

Наші козаченьки - славні запорожці,
Вірними шаблями очищали світ.
Козацькому роду нема переводу,
Прапор малиновий кличе у похід.

Приспів.

Квітне наша доля, наче маки в полі.
І ранкове сонце виплива з дібров.
Козацькому роду нема переводу,
Козаки в коисках виростають знов.

Приспів','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236226'), datetime('now')),datetime('now'));
