INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236354','Веснянка','(Прийди, прийди, весно красна). Музика: Віталій Філіпенко Слова: А. Навроцький. Виконує: Кобза','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Прийди, прийди, весно красна,
Чепури наш рідний край,
Там, там, та-ба-да-ба...

Приспів:
Принеси, весно, нам
Рясні дощі, рясні дощі.
Принеси, весно, нам
Радощі, радощі.
Хай всюди пісня луна,
Пісня луна, пісня луна.
Хай нам зустрінеться
Дівчинонька гарна.

Прийди, весно, в наші села,
Принеси нам дивних див -
Очі синії веселок
З хуртовинами садів.
Там, там, та-ба-да-ба...

Приспів.

Прийди, прийди, весно красна,
Чепури наш рідний край,
Засвіти нам сонце ясне,
З нами в гурті погуляй','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236354'), datetime('now')),datetime('now'));
