INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236292','Шкільна стежина','Музика: В. Мураделі Слова: М. Лисянський','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Через луг, де росте материнка,
Там, де трави рясні, запашні,
В''ється з школи знайома стежинка,
Кожен день я крокую по ній.
В''ється з школи знайома стежинка,
Кожен день я крокую по ній.

Приспів:
Стежинко, перша ти моя,
Лети від школи до порога,
Пройди всі гори і моря
І влийся в сонячну дорогу.
Стежинко, стежинко,
Стежинко ти моя шкільна,
Стежинко, стежинко,
Стежинко ти моя шкільна.

Друже мій і по класу й по парті,
Не одну зустрічать нам весну.
Цілий світ перед нами на карті,
Ми відкриєм свою цілину.
Цілий світ перед нами на карті,
Ми відкриєм свою цілину.

Приспів.

Як настане прощальна година,
Ми залишимо сонячний клас,
І по цій незабутній стежині
Піде наше дитинство від нас.

Приспів.    Фонограма-мінус (mp3, 128kbps)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236292'), datetime('now')),datetime('now'));
