INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2365192','Ой, чого ж ти, мамо?','Музика: Микола Янченко Слова: Микола Янченко. Виконує: Микола Янченко, Таня Денисюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, чого ж ти, мамо, посивіла рано?
