INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2365313','Мамо, лебідко моя','(Чужина...). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Мамо, лебідко моя,
Знов прилетіла весна,
Котра весна вже без тебе,
Хата без тебе сумна...
Жайвір притих десь у небі,
Школа, останній дзвінок, -
Діти щасливі з батьками
Гордо з букетом стоять,
Але без рідної мами...

Приспів:
Мамо, лебідко моя,     |
Сивієш ти на чужині... |
Ласка потрібна твоя,   |
Мама потрібна дитині!  | (2)

Мить пригадалась мені:
Як колискову співала,
В школу за руку вела,
Як треба жити навчала!..
Та пролетіли роки,
Діти з гнізда вилітають,
Десь на чужині батьки
Кращої долі шукають...

Приспів.

Що варте в світі життя,
Любов''ю яке не зігріте?..
Час не повернеш назад,
Ласку не купиш ти дітям...
Скільки ще весен і зим
Буду на тебе чекати?..
Багатство не змінить життя!..
Що втрачене, вже не догнати!..

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2365313'), datetime('now')),datetime('now'));
