INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236653','А в Кривого Танця не вивести Кінця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Веснянки. Українські народні пісні. - К.: Музична Україна, 1988. - С. 83-84.','Гаївки-Великдень: Українське свято Відродження Світа. Гра-коловід Змії/Змія. Весна Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... А ми Йому Кінця не знайдем.','А в Кривого Танця
Та не вивести Кінця.

Веду, веду, та не виведу,
Плету, плету, та не виплету.

Треба Його та виводити,
Кінець йому та знаходити.

Що виведу, то ввірветься,
То Мій Милий засміється','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236653'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236653','А в Кривого Танця не вивести Кінця','А в Кривого Танця
Та не вивести Кінця.

Веду, веду, та не виведу,
Плету, плету, та не виплету.

Треба Його та виводити,
Кінець йому та знаходити.

Що виведу, то ввірветься,
То Мій Милий засміється');
