INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_236515_l1','pisniua_236515','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2367277','Батьківська мова','Музика: Надія Гураль Слова: Алла Бінцаровська','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Тетяна Шарган.','І радісно й святково,
І гордо, і велично
Я мову солов''їну
Несу в піснях у світ!
Бо українське слово,  |
Як та вода кринична,  |
Як у саду калина,     |
Що свій дарує цвіт!   | (2)

Приспів:
Вона - сонцесяйна,
Вона - промениста,
У ній - правіків течія!
Така життєдайна       |
І праведно чиста -    |
Це батьківська мова,  |
Це мова моя!          | (2)

В ній - серця насолода,
Моєї долі крила,
Вона - барвиста мова,
Батьківський заповіт!
У ній душа народу     |
І непоборна сила,     |
У ній незгасна пісня, |
Що лине з роду в рід! | (2)

Приспів.','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2367277'), datetime('now')),datetime('now'));
