INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236591','Розлилися Води на Чотири Броди','Українська народна пісня','uk','ukraine_before_1917',NULL,'1827','1. Малороссійскія пЪсни, изданныя М.Максимовичемъ. - Москва: Въ Типографіи Августа Семена, 1827. - С. 159. 2. Українські пісні, видані М.Максимовичем. - К.: В-во АН УРСР, 1962. - С. 199. 3. Українські народні пісні в записах Софії Тобілевич. - К., 1982. - С. 50. 4. Українські народні пісні з нотами. - Харків.: Фоліо, 2003. - С. 240. 5. http://lib.proza.com.ua/book/142','*В''язка подана за джерелом 5, у джерелах 3 і 4 вона відсутня. **Відміна Максимовича 1827 року подана за джерелами 1 і 2 зі збереженням оригінального правопису (деякі стародавні літери замінені подібними - фахівець розбереться):-) Основний текст пісні поданий за джерелами 3 і 4.','Розлилися води на чотири броди.
Гей, дівки, весна красна, зілля зелененьке.

Що в першому броді зозуленька кує,
Гей, дівки, весна красна, зілля зелененьке.

А в другому броді щука-риба грає,
Гей, дівки, весна красна, зілля зелененьке.

А в третьому броді соловей щебече,
Гей, дівки, весна красна, зілля зелененьке.

А в четвертому броді дівчинонька плаче,
Гей, дівки, весна красна, зілля зелененьке.

Зозуленька кує, бо літечко чує,
Гей, дівки, весна красна, зілля зелененьке.

Риба-щука грає, кригу розбиває,
Гей, дівки, весна красна, зілля зелененьке.

Соловей щебече, травиченьку кличе,
Гей, дівки, весна красна, зілля зелененьке.

Дівчинонька плаче, бо нелюба бачить,
Ой, мати, лихо знати, за нелюбом жити.*
Відміна:**
Розлилися воды
На чотырĕ броды:
У першому бродђ
Соловейко щебетавъ,
Зелены сады розвивавъ;
У другому бродђ
Зозулька ковала,
Лђтечко казала;
У третёму бродђ
Коничок заржавъ,
Вǒнъ дороженьку почавъ;
А въ четвертǒм бродђ
Да дђвчина плаче,
За нелюбого идучы,
Свое лихо чуючи.','["pisni.org.ua", "cat:krasa-pryrody", "cat:vesnyanky-hayivky", "Пісні про красу природи", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236591'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236591','Розлилися Води на Чотири Броди','Розлилися води на чотири броди.
