INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236675','А в Кривого Танцю та не виведу Кінця (2)','Українська народна пісня. Виконує: Христина Охітва','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Гра-коловід Змії/Змія. Весна Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... А ми Йому Кінця не знайдем.','А в Кривого Танцю
Та не виведу Кінця
Треба Його та виводити
Кінець-Ладу ізнаходити','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236675'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236675','А в Кривого Танцю та не виведу Кінця (2)','А в Кривого Танцю
Та не виведу Кінця
Треба Його та виводити
Кінець-Ладу ізнаходити');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236767','Бердо Бердо Бердовичко','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1944','1. Українські народні пісні з Лемківщини. Зібрав Орест Гижа. Заг.ред. С. Грици. Київ „Муз.Україна“ 1972. 403с.','Записана 1944 року від Гатали Олени (1909 р. н.) в селі Висова повіту Горлиці на Лемківщині. Діалектизми: бердовичка - Великодні гаївки; вшытки - всі; дуже - багато; медже - поміж; под - іди, ходи; розийдмеся - розійдімось. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Вже Весна воскресла. Благослови Мати Весну закликати. Под же Дівча медже Нас. Як Нас дуже як величко.','Бердо, Бердо, Бердовичко,
Як Нас мало, невеличко,
Гей, гей, мало Нас,
Под же, Дівча, медже Нас!

Бердо, Бердо, Бердовичко,
Як Нас дуже, як величко,
Гей, гей, дуже Нас,
Розийдмеся вшытки враз!','["pisni.org.ua", "cat:lemkivski", "cat:vesnyanky-hayivky", "Лемківські пісні", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236767'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236767','Бердо Бердо Бердовичко','Бердо, Бердо, Бердовичко,
Як Нас мало, невеличко,
Гей, гей, мало Нас,
Под же, Дівча, медже Нас!

Бердо, Бердо, Бердовичко,
Як Нас дуже, як величко,
Гей, гей, дуже Нас,
Розийдмеся вшытки враз!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2369073','Боже, Україну збережи!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Минає час, минають дні
І змінюється все навколо,
Та тільки Бог Господь - Святий,
Не змінюється Він ніколи!
В одну хвилину може Він
Змінити все в нашій країні,
Господь, благаємо Тебе,
Даруй спасіння Україні!

Приспів:
Боже, Україну збережи!
Господи, помилуй грішних!
Змилуйся над нами і прости,
Молимо Тебе, Всевишній!..
І від ворога нас захисти,
Бо без Тебе ми - безсилі!
Господи, зміни все навкруги,
Дай спасіння Україні!

І як нам всім спостерігать,
Якщо людей отак вбивають,
Коли жива людська душа? -
Вже зовсім цінностей немає...
І як же нам то далі жить,
І нашим дітям в цій країні?
Якщо не вступишся, Господь,
Загине наша Україна...

Приспів.

Дай спасіння Україні!','["pisni.org.ua", "cat:christian", "cat:patriotic", "Пісні на християнську тематику", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2369073'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2369073','Боже, Україну збережи!','Минає час, минають дні
І змінюється все навколо,
Та тільки Бог Господь - Святий,
Не змінюється Він ніколи!
В одну хвилину може Він
Змінити все в нашій країні,
Господь, благаємо Тебе,
Даруй спасіння Україні!

Приспів:
Боже, Україну збережи!
Господи, помилуй грішних!
Змилуйся над нами і прости,
Молимо Тебе, Всевишній!..
І від ворога нас захисти,
Бо без Тебе ми - безсилі!
Господи, зміни все навкруги,
Дай спасіння Україні!

І як нам всім спостерігать,
Якщо людей отак вбивають,
