INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2368096','Добрий день людям на землі!','Музика: Ігор Танчак Слова: Ігор Танчак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Добрий день! Добрий день,
Ниви і поля!
Добрий день! Добрий день,
Матінко земля!
Добрий день! Добрий день
В небі, журавлі!
Добрий день! Добрий день,
Людям на землі!

Приспів:
Це для нас посміхається сонечко,
Соловейко співає пісень!
Заглядає веселка в віконечко:
Добрий день вам! Добрий день!

Добрий день! Добрий день,
Гори і ліси!
Добрий день! Добрий день,
Крапельки роси!
Добрий день! Добрий день,
Квіти запашні!
Добрий день! Добрий день
Людям на землі!

Приспів.

Добрий день! Добрий день,
Дощик степовий!
Добрий день! Добрий день,
Колос золотий!
Добрий день! Добрий день
В морі, кораблі!
Добрий день! Добрий день
Людям на землі!

Приспів.','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2368096'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2368096','Добрий день людям на землі!','Добрий день! Добрий день,
Ниви і поля!
Добрий день! Добрий день,
