INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236697','Ой Вінку Наш Вінку Хрещатий Барвінку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Весна Світа. Еротика, жарти, забави. Гра-коловід Змії/Змія. А ми Йому Кінця не знайдем. А в тій Хаті як у Раю В цьому Дворку як у Вінку! Ой у Лісі й у Лісі на Дубку Піду в Садочок нарву Квіточок Чи вдома вдома Пані Бабуня Чи Дома Дома Микола Дома Щедрик-Щедрик Щедрівочка (1) Золотарю Царю скуй мені Перстеник. Павочка xодить Пір''ячко губить. Йшла Дівчина на Гаївку Пір''ячко збирала. Володар Володар й одчиняй Ворота. Ой Вінку Наш Вінку Хрещатий Барвінку А в тому Саду чисто метено Весна Наша Весна що Ти нам принесла (1) Весно ж Наша Красна що ж Ти нам принесла Весно Наша Весно що Ти нам принесла (3) Вийди вийди Іванку Вийди вийди Іваночку Висиділа Квочка Двоє Куряточок Вінку Ружовий десь був Вінку Ружовий десь був (2) Володар Володар й одчиняй Ворота Воротаре Воротаре вітвори Воротонька Десь тут була Подоляночка Іванку Іванку купи ми Рум''янку Їхав Козак з України по заході Сонця (2) Летів Голуб з Голуб''ятьом в Гороховім Вінку Несе Галя Воду Ой Вінку Наш Вінку Хрещатий Барвінку Ой зав''ю Вінки на всії Святки Пливе Качур в Гороховім Вінку Покотилась по Дорозі Цинова Тарілка Порізала-м Пальчик тай болить Роман Зіля копає Сидить Качур в Гороховім Вінку Що Зброя в Дівчини Віночок Хрещатий. Весна Наша Весна що Ти нам принесла (2) Іва на Купала тай в Воду упала. Гей на Івана гей на Купала Заплету Віночок заплету Шовковий Іване Іваноньку не переходь Доріжоньку На Майдані на Риночку стоїть Сосонка в Барвіночку Ой Вінку мій Вінку Ой на Івана тай на Купала Ой у Лісі й у Лісі на Дубку Пливи Вінок за Водою пливе Доля за Тобою Чий же то Віночок плине по Воді А Наш Вінок Красний як в Небі Місяць Ясний. Вийди Ґаздине до нас відбери Вінок від нас Живо Женчики живо буде Горілочка й Пиво Замітайте Двори застелайте Столи Ми дожали зарана заріжте нам Барана Ой ти Лане-ланочку скажи мені Правдочку Перепелонько Біла де ж ти будеш сиділа На Молоденькій з Барвінку Вінок сіяє. Вийшла Молода на Городчика Горіла Сосна і Явір Горіла Сосна Смерека На Широкій Річці пливуть Каченята Ой а що ж то нам по Нови Сінях палає А я своїй товаришці сплітаю Віночок. Коло мої Хати зацвіли Блавати Надворі червоніє синіє далина Ой ти Місяцю й а Зіронька Ясная Ти казала в понеділок Ти казала в понеділок (2) Виший Хрещатим Барвінком. Люба дружино вкраїнко виший сорочку мені Люба дружино вкраїнко... Не сумуй дівчино мила Ой не цвісти калинонці Я знайшла вінок з барвінку Лежить в Терновому Вінку. Від Синього Дону до Сивиx Карпат Заквітчали Дівчатонька Коли ви вмирали вам дзвони не грали Хай поле виорють гармати Христос воскрес Що за військо іде? Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Стежки до листків про Українські традиції.','Ой Вінку Наш Вінку
