INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236828','Воротай-Воротайчику','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1978','1. Пісні з Поділля. - К.: Музична Україна, 1989. С. 18-19.','Записана 1978 року від Софії Іванівни Гащук (1928 р. н.) в с. Жабинці Чемеровецького району на Хмельниччині.','Воротай-Воротайчику,
