INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2368495','Фантазер','Музика: Олександр Морозов Слова: Богдан Малик. Виконує: Богдан Малик','uk','ukraine_before_1917',NULL,NULL,'https://www.youtube.com/watch?v=ULc7GZ1Iqcs',NULL,'Все я вигадав сам,
Бачити я не міг,
Бо був сильний туман,
Бо був сильний туман
І невипавший сніг...
Пісню ніжних сердець
Під акорди дощу,
Де щасливий кінець,
Де щасливий кінець,
Де тебе я люблю!..
Я приходив!.. Я був
І в мороз, і в жару,
І тобі говорив,
І тобі говорив,
Що тебе лиш люблю!..
І за очі твої
Я відав би усе -
Навіть своє життя!
Та не треба тобі
Неземні почуття!..

Приспів:
Фантазер -
Ти мене називала...
Фантазер,
А ми з тобою - не пара!..
Ти одна!
Ти мені наймиліша!
Ну, а я...
Я люблю все сильніше!..

Промайнув швидко час -
Ти вже з іншим тепер,
І немає вже нас,
І немає вже нас:
Ні теб, ні мене!..
Та тепер в тебе є
Тільки мрії земні,
І земні почуття,
І в наш світ неземний
Вже нема вороття!..

Приспів','["pisni.org.ua", "cat:lirychni", "cat:nostalgia", "Пісні про кохання, ліричні", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2368495'), datetime('now')),datetime('now'));
