INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2369675','Молитва за Україну','Музика: Володимир Хлиста Слова: О. Борис','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Ольга Вельгус.','До Тебе, Господь, у молитві йдемо,
І в Тебе розради шукаєм.
Могутній і сильний, зупиниш Ти зло,
І зглянешся над нашим краєм.

Приспів:
О, Боже, дай нам з неба миру
В кожну сім''ю, в кожну родину!
Благослови всю Україну,
Підтримай в тяжку годину!

В покорі сердець, Боже, ми стоїмо
І вірим в Твоє провидіння.
Хто любить Тебе, все для них на добро,
Чекаємо Твого спасіння!..

Приспів.

Від зору Твого не захований світ,
Ти знаєш думки всі людини.
Теплом милосердя свого нас зігрій,
Згадай про народ України!..

Приспів.','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2369675'), datetime('now')),datetime('now'));
