INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2368920','Краплинки','Музика: Наталія Антоник Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Наталочка Чемерега.','Крапають краплинки,
Їх вже цілий ліс,
Хто ось ці краплинки,
Нам скажіть, приніс.

Приспів:
Дощик, дощик,
Що паде з хмаринки,
Дощик, дощик
Роздає краплинки.

Ніде заховатись,
Скрізь вода біжить,
Хтось, можливо,
Дощик зможе зупинить?..

Приспів.

Ні! Це неможливо!
Не під силу нам.
Дощик, ніби зайчик,
Скаче тут і там.

Приспів.

Непомітно хмарка
Сіра відійшла,
За собою впертий
Дощик потягла.

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2368920'), datetime('now')),datetime('now'));
