INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2370961','Поки любиш','Музика: Христина Соловій Слова: Христина Соловій. Виконує: Христина Соловій','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гори за стіною, а ми тут
Самі під водою з любові...
Море виливається,
Щось всередині починається...
Вільним серце не буде, не буде,
Поки живеш ти, поки любиш...
За минулим сумувати будеш,
Але живеш ти, поки любиш...

Приспів:
А я не бачу більше очі твої...
А я ще хочу знати, що з тобою...
Як ти не бачиш
Скільки було наших сліз гірких?..
Від них колись нам стане краще...

Гори за стіною... І нема вже сил,
А я плачу за тобою...
Якби зупинитися?..
Якби в морі сліз не втопитися?..
Вільним серце не буде, не буде,
Поки живеш ти, поки любиш...
За минулим сумувати будеш,
Але живеш ти, поки любиш...

Приспів.','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2370961'), datetime('now')),datetime('now'));
