INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237216','Ой Весна Весна Днем Красна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Весна іде Красу несе. Принесла я Вам Літечко ще й Рожевую Квіточку. Вже Весна воскресла. А на тій Вербі Рожеві Квіти. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції.','Ой Весна-Весна Днем Красна
Що ж Ти Весно принесла

Принесла я Вам Літечко
Ще й Рожевую Квіточку
Хай вродиться Житечко
Ще й Озимая Пшениця
І Усякая Пашниця

Ой Весна Весна Днем Красна
Що ж Ти Весно принесла

Коробочку з Веретенцями
А Скринечку з Червінцями
Старим Дідам по Кийочку
Старим Бабам по Серпочку
Малим Дітям по Яблучку
А Дівчатам по Віночку
А Хлопчатам по Батожку

Ой Весна Весна Днем Красна
Що ж Ти Весно принесла

Принесла я Вам Літечко
Ще й Запашненьке Зіллячко
А Вам Дівчата по Вінку
З Хрещатого Барвінку
А Вам Парубки по Кийку
Гоніте Товар на Гірку
А Вам Бабусі по Ціпку
Попід Хатами ходити
Малих Діточок глядіти

Ой Весна Весна Днем Красна
Що ж Ти Весно принесла

Принесла я Вам Літечко
Ще й Запашненьке Зіллячко
Ще й Зеленую Травицю
І Холодную Водицю
Принесла я Вам Ягнятко
Ще й Маленькеє Телятко','["pisni.org.ua", "cat:lirychni", "cat:narodni", "cat:vesnyanky-hayivky", "Пісні про кохання, ліричні", "Народні пісні", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237216'), datetime('now')),datetime('now'));
