Ще й Маленькеє Телятко');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2373550','В добрий час','Музика: Микола Ведмедеря Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'В добрий час, зимовий час
Розцвіла ялинка в нас,
Кульки на ялиночці,
Ніби намистиночки.
Кольорами мерехтять,
Привітати всіх хотять.
Зі святами, з Новим роком,
З впевненим, надійним кроком!

Приспів:
З Новим роком, в добрий час
Радість хай прийде до вас!
Сміх, мов пісня, дзвінко ллється,
Хай вам успіх усміхнеться!
Хай сніжок біленький пух
Припорошить ваш кожух,
Рукавички припорошить,
І до танцю всіх запросить!

В добрий час, зимовий час
Всі зібрались водночас,
Одягнув хтось маску,
Щоб зіграти казку!
Хтось танцює, хтось співа,
Хтось вірша усім чита.
Зі святами, з Новим роком,
З впевненим, надійним кроком!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2373550'), datetime('now')),datetime('now'));
