INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374022','Тихий ліс, попід лісом шанси','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930','аудіозапис','Місце побутування: смт Запитів, Кам''янка-Бузький район, Львівська область. Респондент: Максимишин Марія Олексіївна, 1930 р.н. Збирачі: Вовчак Андрій, Мартиник Соломія.','Тихий ліс, попід лісом шанси
В сяєві і мареві заграв,
Втомлені стрільці поснули вранці,
Вартовий їх сон уберігав.

Тихо-тихо полем вітер віє,
Шелестить, торкнувшися листя,
І летять у даль солодкі мрії
Вартового юного стрільця:

Ось він вдома, вийшли брати, сестри,
Стара мати в білому чіпку...
І в той час позаді десь на дубі
Закувала зозуля: Ку-ку.

Ой, чого ж ти закувала зрання?
Ти збудила чар солодких снів.
Відгадай, скажи мені, кохана,
Скільки років я ще буду жив?

Байдуже кує собі зозуля:
Рраз і другий, третий і кінець.
Те кування перервала куля -
Похиливсь прострілений стрілець.','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374022'), datetime('now')),datetime('now'));
