INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2373216','Мамине сонечко','Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Каже мені мама, що я ще мала
І не розумію деякі слова,
Слухатись не хочу,
Мов бджілка, літаю
І про все, що каже мама,
Забуваю...

Приспів:
Мамочко, мамо,
Я - твоя краплинка,
Квіточка, сонечко,
Доня-горошинка!
Ну пробач, будь ласка,
Більше так не буду!
Я, як підросту,
Слухатися буду!

Мама посміхнулась, мене притулила
І сказала ніжно: Я така щаслива,
Що у мене є сонечко маленьке,
Яке зігріває тривожне серденько!"

Приспів.    Фонограма-мінус (mp3, 320 kbps)  (','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2373216'), datetime('now')),datetime('now'));
