INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2373369','Буде гарний Новий рік!','Музика: Сєрж Озерян Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'В білих шубах зайченята
Мандрували по санчата.
Плиг, скік, плиг та скік,
Буде гарний Новий рік!

Всі санчата дружно взяли,
До ялинки пострибали.
Плиг, скік, плиг та скік,
Буде гарний Новий рік!
Тра-ля-ля-ля-ля-ля-ля,
Зимонька-зима!

Вже красуня зачекалась,
В срібні вогники прибралась,
Плиг, скік, плиг та скік,
Буде гарний Новий рік!

Радо, весело на святі
Пританцьовують вухаті.
Плиг, скік, плиг та скік,
Буде гарний Новий рік!    Людмила Ясінська feat. Мілі & Ромі Дамрі - Буде гарний Новий рік!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2373369'), datetime('now')),datetime('now'));
