INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237414','Ой п’є Байда Мед-горілочку','Українська народна пісня. Виконує: Павло Плішка','uk','ukr_ssr_1919_1991',NULL,'1958','1. Українські релігійні роздуми про Спасіння © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2003 2. Українські народні пісні у записах М. Лисенка. Комплект листівок. Художник А. Базилевич. - К.: Мистецтво, 1966','Ноти у джерелі 2 подані за: М. В. Лисенко. Зібрання творів у двадцяти томах. - К.: Мистецтво, 1958 Байда. Чи випадково це ім''я нагадує про Будду, Просвітленого, чи Вайду? а розп''яття Байди на Дубочку – про Суса Хреста? Пісня про Байду. Про що Вона? Чи це не Українська пісенна оповідь про Спасителя, Страсті Господні і Воскресіння, у світі не по Правді? Чому така схожість з новозавітньою символікою? Чому Цар звертається шанобливо: "Ой бо що ж Ти робиш Байдо Молодецький?". Хіба не дивно, що він шанує такого собі ніби-то гультяя, який п''є "не день, не нічку та не годиночку"? Яку Силу Цар відчуває чи знає за Байдою? Якщо описано історичну подію, зіткнення між козаками та турками, то чому Цар-завойовник, в повній волі якого ніби-то опиняється Байда (за наказом Царя його слуги зв''язують Байду без видимих знаків опору чи боротьби), пропонує Байді родичатися та царювати? Чому Байда не опирається, коли його хапають цареві слуги? Що бачить Байда? Чому саме Голубочків на Дубочках? Чому Байду розп''ято на Дубочку? Воскресна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. У Чистому Степу собі Живности доставати. Байді Молодому Мед-горілку пити. Ой що Ти бачиш Байдо Молодецький. Многая Літа да посієм Жито. Приїдь Синочок напийсь Води. Ой устань же Козаченьку. В Царіграді на Риночку Ой на Горі на Могилі Ой п''є Байда Мед-горілочку Там на Кубані єсть Брюховецька Я ще не вмер, в очах ще промінь сяє А чи мені Господь дав чи Свята Варвара Гей наливайте Повнії Чари Дякуймо Вам Файні Ґазди Ой у Саду Вишневому там Пташки поють Ой хто п''є тому наливайте Ой хто п''є тому наливайте (2) Як засядем Браття Коло Чари Чого Старий не женишся. Но ми докажем своїм Клинком. Іще живі та здорові Всі Родичі Гарбузові. Там гуляла Бондарівна як Пишная Пава. У Містечку Богуславі Танець Дівок ходить. Ой не годен пан Каньовський мене цілувати. Куди несли Бондарівну крівавая річка. Повели ж Його Морозенка на Савур-могилу. За тобою Морозенко вся Вкраїна плаче. Подивися Морозенку тай на свою Україну. Ой устань же Козаченьку. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой п''є Байда Мед-горілочку
Та не день не нічку та не годиночку   |(2)

Прийшов до нього Цар Турецький
Ой що ж бо Ти робиш Байдо Молодецький |(2)

Ой п''ю Царю Мед-горілочку
Та не день не нічку та не годиночку   |(2)

Покинь Байдо байдувати
Сватай мою Дочку та йди царювати      |(2)

Твоя дочка поганая
Вся Турецька Віра-віра проклятая      |(2)

Ой як крикне Цар Турецький
Та на свої Слуги-слуги молодецькі     |(2)

Візьміть Байду ізв''яжіте
Та за ребро гаком-гаком зачепіте      |(2)

Взяли Байду ізв''язали
Та й за ребро гаком-гаком зачіпали    |(2)

Висить Байда на Дубочку
Та не день не нічку та не годиночку   |(2)

Прийшов до нього Цар Турецький
Ой що Ти бачиш Байдо Молодецький      |(2)

Бачу Царю Два Дубочки
А на  Тиx Дубочкаx сидять Голубочки   |(2)

Дозволь Царю Лучка взяти
Тобі на вечерю Голубочка зняти        |(2)

Ой як стрельнув Байда з Лука
Та попав Царя поміж самі вуxа         |(2)

А Царицю в потилицю
А Цареву дочку в саму головочку       |(2)

Тобі Царю в землі гнити
Байді Молодому Мед-горілку пити       |(2)','["pisni.org.ua", "cat:dumy", "cat:kozacki", "cat:philosophic", "Думи", "Козацькі пісні", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237414'), datetime('now')),datetime('now'));
