INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2373961','А ми наступали темнинької ночі','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1958','аудіозапис','Місце побутування: с. Боберка, Боберківська сільрада, Турківський район, Львівська область. Респонденти: Возняк Ганна Луківна, 1958 р.н., Гошко Люся Ільківна, 1941 р.н., Проньо Василь Дмитрович, 1970 р.н., Проньо Надія Іванівна, 1970 р.н. Збирачі: Іванищук Марія, Беднарська Ружена.','А ми наступали темнинької ночі,
А ясні зорі сіяли,
Гармати били, а ми наступали,      |
Один по другому падав.             | (2)

Бачив, я бачив раненого друга,
Він впав на землю ще живий,
З грудей червона кров текла рікою, |
Останні слова говорив:             | (2)

Напишіт до батька, напишіт до неньки,
Напишіт до рідної дівчини,
Що гостра куля грудь мою пробила   |
О пів до другої години.            | (2)

Не було там батька, не було там неньки,
Не було там рідної дівчини,
Лиш мої друзі, друзі заплакали,    |
Оркестра жалібно заграла.          | (2)','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2373961'), datetime('now')),datetime('now'));
