INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374694','Ми вас вітаємо!','Музика: Алла Чепикова Слова: Алла Чепикова','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконують Білі Крила і Алла Чепикова.','Зірка сяє з Небес для нас
У різдвяний, святковий час!
До Ісуса нас кличе!       |
Підемо туди,              |
Привітаєм Царя Землі!     | (2)

Приспів:
Ми вас вітаємо,
І вам бажаємо
Миру та любові в серцях!
Ми бажаємо всім:
Нехай прийде в ваш дім
Благословення з небес!

Кличе до Вифлеєму всіх,
Щоб залишити всякий гріх
Та Поспішати туди,        |
Де чекає нас Божий Син    |
Кожен день, кожен час.    | (2)

Приспів.

У Величний цей День Різдва
Линуть в Небо нехай слова:
Тобі дякую Ісус,          |
Що в цей Світ Ти прийшов, |
Та для Неба мене знайшов! | (2)

Приспів.','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374694'), datetime('now')),datetime('now'));
