INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374313','Різдво прийде','Музика: Гурт Єдність Слова: Гурт Єдність','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Проект створено за ініціативою та фінансовою підтримкою гурту "Єдність".','Різдво прийде у кожен дім,
Дарує радість нам усім!
Послав Господь святковий день
Для молитов і для пісень!

Приспів:
Славимо! Славимо
Боже дитя!
Христос народився!
Богу хвала!

На дворі гарно, сніг іде,
Нам ангел новину несе:
Сьогодні свято на землі,
Славімо Господа усі!

Приспів. (2)

Зійшла зоря над нами в ніч
І свято скрізь, лунає сміх!
Лиш подивись, щасливі всі!
Христос родився на землі!

Приспів. (2)

Славимо! Славимо
Боже дитя!
Христос народився!
Світу явився!
Богу хвала! Богу хвала!
Богу хвала!
Славимо! Славимо!
Славимо! Славимо
Боже дитя!    Фонограма-мінус (mp3, 128 kbps)','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374313'), datetime('now')),datetime('now'));
