INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374457','Чорний ліс','Музика: Святослав Клім Слова: Святослав Клім','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'В білий день і в темну ніч
Ми ідем в Карпатський ліс,
Бо там наші хлопці ждуть,
Разом з нами в бій ідуть!

Приспів:
Чорний ліс то наша хата,
А Бандера то наш тато.
Ненька наша - Україна,
Рідна мова - солов''їна!

Рідний брате, не сумуй,
В бій ідемо, ти воюй!
За рідненьку Україну
Будем битись до загину!

Приспів.

Як загинем ми в бою,
Не сумуй ти без краю.
Пам''ятайте, Ви про нас
Покоління - цвіте наш.

Приспів.','["pisni.org.ua", "cat:halycki", "cat:povstanski", "cat:rekrutski", "Пісні з Галичини", "Повстанські пісні", "Рекрутські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374457'), datetime('now')),datetime('now'));
