INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374328','В синім небі засіяла зоря',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В синім небі засіяла зоря,
Ясно, ясно світить вона,
Усім людям звіщає вона
Про Різдво Христове!
Народився нам Божий Син,
Він зійшов до нас з небес,
Щоб спасти нас від гріха
І спасіння вічне дати!

Приспів:
Христос народився!
Христос народився!
В цю Різдвяну дивну ніч
Народився Божий Син!
Христос народився!
Христос народився!
Славу ми Йому несем
І поклін Йому складем!
Христос народився!

В день Різдва ми вітаємо вас!
В день Різдва ми співаєм для вас
Пісню про Різдво Христа,
Дивну пісню хваління!
Хай засяє вона в небесах
І розбудить у ваших серцях
Вогник віри в Ісуса Христа
І надію в спасіння!

Приспів.','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374328'), datetime('now')),datetime('now'));
