INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2374624','Радій, співай, Ісуса слав!',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Радій, співай, Ісуса слав,
Бо день Різдва настав!

Колись в містечку Вифлеєм -
Каже Біблія свята -
Марія Діва Сина там
Сповила в день Різдва!

Приспів:
Слава в вишніх, мир землі!
Вам народився Цар!
Для вас Бог дав Спасителя!
Хор ангельський співав!

Там пастухи овець пасли,
Побачили нову зорю,
Почули дивний спів з небес,
Вклонились там Дитятку Царю!

Приспів.

Хай радіють всі люди землі,
Хай дзвенять всі дзвони
В цей день Різдвяний!
І хай буде мир на землі,
І в серцях лине Богу хвала!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2374624'), datetime('now')),datetime('now'));
