INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237550','Йшла Дівчина через Двір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Сито і Відро — де тут символ Дівчини, а де Парубка?:-) Чиї старання подібні до Сізіфових чи Данаїд?:-)) У кого-таки більше правди і в чому вона полягає?:-))) Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Десь узялася Молода Дівчина. Стала ж Вона сяяти. Стали Хусточки маяти cтала Діброва палати. Скільки в Цебрі Водиці cтільки в Дівчат Правдиці. А ми в Кривого Танцю йдем Ішли Дівки через Двір Йшла Дівчина через Двір На Городі Корито Корито Ой йшла Дівка через Двір Горіла Сосна палала. А ми Йому Кінця не знайдем. Листки з приводу цієї Пісні: Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май. Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень — Українське Свято Відродження Світа. (Вибір Пісень)','Йшла Дівчина через Двір через Двір через Двір
На Ній Сукня в Дев''ять Піл в Дев''ять Піл в Дев''ять Піл

