INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2375591','Відлітають в небо журавлі','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ще не віриться нам, що ми
На порозі дитинства стали,
А ще вчора були дітьми
Й каруселі на нас чекали.
А сьогодні останній раз
Продзвенів золотий дзвіночок,
Ми заходимо тихо в клас
І ховаємо мокрі очі...

Приспів:
Відлітають,
Відлітають в небо журавлі,
Нас в дорогу проводжає
Школа на зорі...
Прощавай, дитинство миле,
Дзвоник золотий,
Рідна школа, галаслива,
За усе прости...

Вже не віриться, двір шкільний
Більше дзвоником не зустріне
І країна дитячих мрій
Свої двері нам не відкриє.
І сьогодні останній раз
Продзвенів золотий дзвіночок,
Ми заходимо тихо в клас
І ховаємо мокрі очі...

Приспів.','["pisni.org.ua", "cat:nostalgia", "cat:shkilni", "Пісні з ностальгічними мотивами", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2375591'), datetime('now')),datetime('now'));
