INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23767','Ой, зав''ю вінки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Традиційна українська веснянка.','Ой, зав''ю вінки на всії святки.
На всії святки,на празднички.
На всії святки,на празднички

Приспів:
Ой, леле, рано, та й ранесенько,
Щоб сонце глянуло веселесенько.       | (2)

В бору сосна колихалась,
Дочка батька дожидалась.
Дочка батька дожидалась.

Приспів:
Ой, прилинь, прилинь,та, мій батечко
Мій голубчику, хоч на літечко.        | (2)

Синєє море розливається,
Пани, гетьмани з''жджаються.

Приспів:
Ой, леле, рано, та й ранесенько,
Щоб сонце глянуло веселесенько.       | (2)','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23767'), datetime('now')),datetime('now'));
