INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2377798','Прощай, дівчино, бо я вже йду','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісня походить з Кубані, була перероблена січовими стрільцями. Записана на Покутті.','Прощай, дівчино,
Бо я вже йду,
Благослови ня
На ту війну!..

Прощай, дівчино...
Прощай... Прощай... -
Я йду до бою
За рідний край!

Летіла куля
Попід гору
Та й ударила
У грудь мою!

Потекла кровця
Річенькою,
Аж до тихого
Та й Дунаю...

А в тім Дунаю
Бистра вода,
Вже ж того хлопця
В світі нема...','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2377798'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2377798','Прощай, дівчино, бо я вже йду','Прощай, дівчино,
