INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2378697','Бік пробитий',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Бік пробитий,
Нам відкритий струмінь спасіння,
Кров тече, тече вода −
Ціна іскупління.
Хрещення і Євхаристія −
Ось тайни нового життя,
Це Пасха Божого Христа,
Тож всі прийдіть до джерела!
Прийдіть до джерела!

Від страждань в Єрусалимі
І аж до нині,
Від години мук Христових
Є нам можливим
Народитись знову
Від води й Духа Святого,
Щоб ввійти до Царства Бога!
Як прекрасна ця дорога до небес!..
Дорога до небес!..

Чи ти знаєш, що шукаєш,
Що в Бога просиш?
Чи прийняти зможеш чашу
Й хрещення також?
Важко є докіль не здійсниться
Це хрещення, що маю
Я прийняти із руки Отця! −
Це є Ісусові слова.
Ісусові слова.

Подивись і поклонись,
Бо ти є християнин!
Гідність це є плід хреста!
Від смерті ти спасен!
Тут є ціла таємниця:
Той, хто в смерть Христову
Зануриться,
Знову до життя родиться,
Щоб із Богом вічно жить,
З Богом вічно жить!','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2378697'), datetime('now')),datetime('now'));
