INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237797','Ой Морозе Морозенко ти Славний Козаче','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Морозенко, як і Байда, — Український символ Спасителя. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Повели ж Його Морозенка на Савур-могилу. За тобою Морозенко вся Вкраїна плаче. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой Морозе-Морозенко ти Славний Козаче
За тобою Морозенко вся Вкраїна плаче...

Не так всяя Україна як Рідная Мати
Заплакала Морозиха стоя біля Хати...

Не плач не плач Морозихо об/о сирую землю не бийся
Іди з нами Козаками Мед-вина напийся...

Ой щось мені Козаченьки Мед-вино не п''єцця
Ой десь мій син Морозенко з ворогами б''єцця...

Не вернувся Морозенко голова завзята
Замучили Молодого вороги прокляті...

Замучивши поставили на Савур-могилу
Подивися/подивись тепер Морозенко на свою Вкраїну','["pisni.org.ua", "cat:dumy", "cat:kozacki", "cat:philosophic", "Думи", "Козацькі пісні", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237797'), datetime('now')),datetime('now'));
