INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2377267','Марш перемоги','(Чи чуєш, юначе?). Музика: Леопольд Ященко Слова: Леопольд Ященко. Виконує: Етнографічний хор Гомін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Чи чуєш, юначе:
Вітчизна нас кличе!
Отож не гайся, уставай -
На нас чекає рідний край!

Могутня і єдина
Скресає Україна,
Благословенна сторона,
Що в цілім світі одна!

Прийшла весна й на наше поле,
Прослала нам свій світлий шлях!
І вже не спинить нас недоля,
Наш прапор в міцних руках,
Міцних руках!

Ми разом! Нас багато!
І нас нікому не здолати!
Бо наша сила все зроста!
Бо нас єднає ясна мета!

Стояти за свободу!
Служити своєму роду!
В ім''я прийдешніх
Світлих днів,
Вовіки віків!','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2377267'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2377267','Марш перемоги','Чи чуєш, юначе:
