INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2379797','Гей, чули, чули, чули?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','На мелодію пісні "Із сиром пироги".','Прийшли ми всі на свято,
На свято Букваря,
І вивчили всі букви,
Усі від А до Я!

Приспів:
Гей, чули, чули, чули,  |
Гей, чули, чули ви?     |
З Буквариком ми дружим, |
Він з нами назавжди!    | (2)

У нас сьогодні свято,
Шануєм Букваря,
Відкрив він нам дорогу
До знань від А до Я!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2379797'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2379797','Гей, чули, чули, чули?','Прийшли ми всі на свято,
