Приспів.    Дует "Горислава" Анна Мудра і Людмила Близнюк');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2381515_l1','pisniua_2381515','YouTube','https://www.youtube.com/watch?v=mO7EZTLana4','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2380395','Гей, беньки-беньки, бубеньки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','*пінязі - гроші (зі словника лемківської говірки).','Гей, беньки-беньки, бубеньки,
Гей, беньки-беньки, беньки-бубеньки,
Бубеньки-беньки!..

А в тих бубеньках пінязі*,
А в тих бубеньках пінязі-пінязі.
Нязі-пінязі!..

Підеме з ними до места,
Підеме з ними до места, до места,
До места-места...

Купиме за ні пшениці,
Купиме за ні пшениці-пшениці,
Пшениці-ниці!..

Підеме ми з ньом до млина,
Підеме ми з ньом до млина, до млина,
До млина-млина...

Дай, Боже, щєстя млинарю,
Дай, Боже, щєстя млинарю-млинарю,
Млинарю-нарю...

Змель же нам тоту пшеницю,
Змель же нам тоту пшеницю, пшеницю,
Пшеницю-ницю...

Будеме печи колачи,
Будеме печи колачи-колачи,
Колачи-лачи!..

Будеме давац убогим,
Будеме давац убогим-убогим,
Убогим-богим...

Жеби ся за нас молили,
Жеби ся за нас молили-молили,
Молили-лили...

І Пана Бога просили,
І Пана Бога просили-просили,
Просили-сили...','["pisni.org.ua", "cat:kolyskovi", "cat:lemkivski", "Колискові", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2380395'), datetime('now')),datetime('now'));
