INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238175','Гуляють українські козаки','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_before_1917',NULL,NULL,NULL,'Збірка пісень "КОРАБЛИК"','Час настає і працьовиті всі такі,
Ось, на свята зібрались наші козаки
І щедрий стіл в саду накрили залюбки
Дівчата їхні і вродливі, і стрункі.
Приспів 1:
Бадьора музика Ви чуєте гримить,
Лунає пісня і дівочий сміх звучить
І гупотять у танцях міцні каблуки, -
Гуляють добрі українські козаки!
Музика,ой, як дуже гарно виграє,
Дівоче серце, наче, щастю віддає,
Бо біля неї молодий такий козак
Танцює спритно всім знайомий наш гопак.
Приспів 2:
Бадьора музика Ви чуєте гримить,
Лунає пісня і дівочий сміх звучить
І гупотять у танцях міцні каблуки, -
Гуляють стильні українські козаки!
Нехай війна і різні кляті вороги
Не зазіхнуть на землі наші ці святі,
Бо пам''ятає завжди весь Козацький рід
Свого Великого Шевченка Заповіт.
Приспів 3:
Бадьора музика Ви чуєте гримить,
Лунає пісня і дівочий сміх звучить
І гупотять у танцях міцні каблуки
Гуляють славні українські козаки!','["pisni.org.ua", "cat:bardivski", "cat:kozacki", "cat:zahalni-cinnosti", "Бардівські пісні", "Козацькі пісні", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238175'), datetime('now')),datetime('now'));
