INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2380471','Ой, ти, коте сірий','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, ти, коте сірий,
Ой, ти, коте сірий,
Вимети нам сіни,
Вимети нам сіни,
Вимети нам сіни...

Ой, ти, коте чорний,
Ой, ти, коте чорний,
Сідай в срібний човен,
Сідай в срібний човен,
Лови рибки повен...

А, ти, коте рудьку,
А, ти, коте рудьку,
Та витопи грубку,
Та витопи грубку,
Та витопи грубку...

Щоб було тепленько,
Щоб було тепленько
Твоєму серденьку,
Твоєму серденьку,
Твоєму серденьку...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2380471'), datetime('now')),datetime('now'));
