INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_237859','Гей, соколи','Виконує: Володимир Вермінський, Гурт "Зоряна ніч"','uk','ukraine_before_1917',NULL,NULL,'1. Аудіо-CD "Володимир Вермінський. Йшли селом партизани 2" (2005) 2. Пісня "Соколи" 3. Форум "Вогнем і Мечем"','Текст взято із джерела 2, виправлено і доповнено за джерелом 1. Акорди підібрано на слух за джерелом 1, спрощено. Оригінальна тональність: Fm (каподастр на I ладі). * Тут у джерелі 1: "Плаче, жаль, молода дівчина". Спрощено за джерелом 2 для більш зручного співання. ** Тут послідовність "H7 Em H7 G D" можна замінити на "H7 Em D". Підбір акордів: bohdanko (pisni.org.ua)','Вступ: | G | D H7 | Em | H7 Em H7 Em |
Em
Гей, десь там, де чорні води,
H7
Сів на коня козак молодий.
Em
Плаче молода дівчина,*
H7          Em H7 G D **
Їде козак з Укра_ їни.
Приспів:
G
Гей, гей, гей, соколи,
Оминайте гори, ліси, доли.
Em
Дзвінь, дзвінь, дзвінь, дзвіночку,
Степовий жайво_ ро_ ночку!
G
Гей, гей, гей, соколи,
Оминайте гори, ліси, доли.
Em
Дзвінь, дзвінь, дзвінь, дзвіночку,
Мій степовий, дзвінь, дзвінь, дзвінь!
Жаль, жаль, за милою,
За рідною стороною.
Жаль, жаль, серце плаче,
Більше її не побачу.
Приспів.
Плаче, плаче, дівчинонька,
Люба моя ластівонька.
А я у чужому краю,
Серце спокою не має.
Приспів.
Меду-вина наливайте.
Як загину - поховайте
На далекій Україні
Коло милої дівчини.
Приспів.
Варіант пісні польською мовою
(за джерелом 3):
1. Oj, tam gdzieś z nad czarnej wody
Siada na koń kozak młody.
Czule żegna się z dziewczyną,
Jeszcze czulej z Ukrainą.
Refr.:
Hej, hej, hej, sokoły!
Omijajcie góry, lasy, doly.
bis Dzwoń, dzwoń, dzwoń dzwoneczku,
Moj stepowy skowroneczku.
Moj stepowy dzwoń, dzwoń, dzwoń. (2)
2. Ona jedna pozostała,
Przepióreczka moja mała.
A ja tutaj w obcej stronie
Dniem i nocą tęsknię do niej.
3. Pięknych dziewcząt jest nie mało,
A najwięcej w Ukrainie.
Tam me serce pozostało
Przy kochanej mej dziewczynie.
4. Wina, wina, wina dajcie,
A jak umrę, pochowajcie
Na zielonej Ukrainie,
Przy kochanej mej dziewczynie.','["pisni.org.ua", "cat:lirychni", "cat:manrivni", "Пісні про кохання, ліричні", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_237859'), datetime('now')),datetime('now'));
