Українців у найми послала...

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2379550','Букварик','Музика: Анна Олєйнікова Слова: Лариса Ратич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми навчилися читати -
Ось які у нас дива!
Вмієм букви розбирати
І складати у слова!
І слова-рядочки в казку,
Як струмочок потечуть,
Стануть букви густо-рясно,
Тиху розповідь почнуть.

Приспів:
Букварику, Букварику,
Ти - вірний друг школярику,
Його надійний провідник
В країну різних знань!
Букварику, Букварику,
Допоможи школярику
Знайти стежину в світі
Книг і добрих сподівань!

Ми навчилися читати -
Подорослішали вмить!
Тож сестричку або брата
Теж зуміємо навчить.
А забуде окуляри
Десь дідусь у певний час -
Допоможемо, звичайно,
Прочитаємо нараз!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2379550'), datetime('now')),datetime('now'));
