INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382063','Ой, калино-луговино','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, калино-луговино,
Чого в лузі стоїш,
Чи сонечка визираєш,
Чи дощу ся боїш?

Не сонечка визираю,
Не дощу ся бою,
Де ня мамка породила,
Я си там постою.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382063'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382063','Ой, калино-луговино','Ой, калино-луговино,
Чого в лузі стоїш,
Чи сонечка визираєш,
Чи дощу ся боїш?

Не сонечка визираю,
Не дощу ся бою,
Де ня мамка породила,
Я си там постою.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382293','Ой, дівчино, молодийка, ти ходи за мене','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, дівчино, молодийка,
Ти ходи за мене,
Не буде ти за роботу
Тяжийко у мене.

Їсти варити не будеш,
Бо не буде з чого,
І до стаєнки не підеш,
Бо нема до чого.

Хоч не буду вечеряти,
Хоч не буду їсти,
А буду мати попри кого
Межи людьми сісти.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382293'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382293','Ой, дівчино, молодийка, ти ходи за мене','Ой, дівчино, молодийка,
Ти ходи за мене,
Не буде ти за роботу
Тяжийко у мене.

Їсти варити не будеш,
Бо не буде з чого,
І до стаєнки не підеш,
Бо нема до чого.

Хоч не буду вечеряти,
Хоч не буду їсти,
А буду мати попри кого
Межи людьми сісти.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382369','Ой, зелений барвіночку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, зелений барвіночку,
Стелися ще нижче,
А ти, милий чорнобривий,
Присунься ще ближче.

Ой, летіли білі гуси
Від броду до броду,
Як ся файно подивити
По моєму роду.

Ой, весілля, товаришу,
Весілля, весілля,
Через чужі молодиці
Не маю спасіння.

Широкий лист на трепеті,
Ширший на яворі,
Прийми, мамко, подарунки
Від жіночки мої.

Прийми, мамко, подарунок
Від жіночки мої,
Та заховай на пам''ятку
Від невістки свої.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382369'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382369','Ой, зелений барвіночку','Ой, зелений барвіночку,
