INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382111','Ой, що ти си, дівчинонько, гадала?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, що ти си, дівчинонько,
Гадала, гадала,
Як зелена полонинка
Палала, палала?

Я гадала полонинку
Гасити, гасити,
Та не могла з-під явора
Води наносити.

Летів пташок понад верхи,
А я ся дивила,
Ой, який то пташок файний,
Коби-м ся імила.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382111'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382111','Ой, що ти си, дівчинонько, гадала?','Ой, що ти си, дівчинонько,
Гадала, гадала,
Як зелена полонинка
Палала, палала?

Я гадала полонинку
Гасити, гасити,
Та не могла з-під явора
Води наносити.

Летів пташок понад верхи,
А я ся дивила,
Ой, який то пташок файний,
Коби-м ся імила.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382251','Ой, по вашій, кумцьо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, по вашій, кумцьо,
Стрісі лазили качата,
Дай вам, Боже, молодята,
До року близнята.

Ой, зацвіло, кумцьо, зілля
На ґанку, на ґанку,
Таку маєш, хлопче, жінку,
Як з театру ляльку.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382251'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382251','Ой, по вашій, кумцьо','Ой, по вашій, кумцьо,
Стрісі лазили качата,
Дай вам, Боже, молодята,
До року близнята.

Ой, зацвіло, кумцьо, зілля
На ґанку, на ґанку,
Таку маєш, хлопче, жінку,
Як з театру ляльку.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238158','Плавай плавай Лебедонько','Музика: народна Слова: Тарас Шевченко. Виконує: Кубанський Козачий Хор, Оксана Петрусенко, Клавдія Радченко, Тетяна Негрій','uk','ukr_ssr_1919_1991',NULL,'1960','1. Плавай, плавай, лебедонько. Народні пісні на слова Тараса Шевченка. Вид. 3, доповнене. Упор., вступна стаття та примітки О.А. Правдюка. Київ, "Муз.Україна" 1989. 159с. 2. Українські народні романси. - К.: В-во АН УРСР, 1961. - 411 с. 3. Народні пісні на слова Тараса Шевченка. - К.: В-во АН УРСР, 1961. - 240 с. 4. http://poetry.uazone.net/kobzar/topola.html','*За джерелами [1, 3]: записана у вересні 1960 р. від Ю.П.Симоненко і Н.К.Малюкової в м. Прилуки на Чернігівщині. Розшифрував О.А.Правдюк. Цьому тексту у джерелі [3] відповідають додані у файлі ноти, але у джерелі [1] подані ноти із джерела [2]. У джерелі [3] подані 6 відмін мелодій пісні. Пісня — переспів уривку з поеми "Тополя" Тараса Шевченка [4] **Відміна подана за джерелом [2]: записана 1959 р. в м. Баришівка Київської області від Н.О.Онищенко. Розшифрував О.А.Правдюк. А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. Листки з приводу цієї Пісні: Ой у Вишневому Саду там Соловейко щебетав А в Пана Йвана Золота Верба Стежки до листків про Українські традиції.','Плавай-плавай Лебедонько
По Синьому Морі
Рости-рости Тополенько
Все вгору та вгору

Рости Гнучка та Висока
До самої Хмари
Спитай Отця спитай Неньки
Чи діжду я Пари

Спитай Отця спитай Неньки
Що вони думають
Що єдину Дочку мали
А тепер не мають

Отак тая Чорнобрива
Плакала-співала
І на Диво усім людям
Тополею стала *
Відміна:**
Плавай-плавай Лебедонько
По Синьому Морю
Рости-рости Тополенько
Все вгору та вгору

Рости Гнучка та Висока
До самої Хмари
Спитай Бога чи діжду я
Чи не діжду Пари

Рости-рости подивися
За Синєє Море
По тім боці - моя Доля
По сім боці - Горе

Там десь Милий Чорнобривий
Співає-гуляє
А я плачу Літа трачу
Його виглядаю

Скажи Йому Моє Серце
Що сміються люди
Скажи Йому що загину
Коли не прибуде !','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238158'), datetime('now')),datetime('now'));
