INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_238158_l1','pisniua_238158','YouTube','https://www.youtube.com/watch?v=GbnemYk78Zw','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382199','Ой, йшли дівки на весілля','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, йшли дівки на весілля
Та й таке повіли:
А ми нині борщ варили,
А пироги їли.

А хлопаки ішли ззаду
Та й ся прислухали,
А як прийшли на весілля,
То так заспівали:

Беріть; хлопці, тоту в танець,
Що пироги їла,
Лиш помали обертайте,
Би ся не розсіла.

Ой, я прийшла на весілля
Не їсти, не пити,
А я прийшла на весілля
Людей веселити.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382199'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382199','Ой, йшли дівки на весілля','Ой, йшли дівки на весілля
