INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382512','А ти, дедю, до роботи','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А ти, дедю, до роботи, —
Косити, орати,
А я, дедю, до гуляння, —
Гуляти, співати.

А ти, дедю, до роботи,
Коби була нивка!
А я, дедю, до гуляння,
Коби чорнобривка!','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382512'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382512','А ти, дедю, до роботи','А ти, дедю, до роботи, —
