INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382596','А музика в коршмі грала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А музика в коршмі грала,
А я не ходила,
Добрий мати розум мала,
Що мня не пустила.

Добрий мати розум мала,
Що мене замкнула,
Була б я ся, молоденька,
Віночка позбула.

Ой, щось я ся розспівала,
Щось буду плакати,
Будуть мене тато бити,
А мама тримати.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382596'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382596','А музика в коршмі грала','А музика в коршмі грала,
А я не ходила,
Добрий мати розум мала,
Що мня не пустила.

Добрий мати розум мала,
