Будуть мене тато бити,
А мама тримати.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382277','Ой, не тішся, дівчинонько','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, не тішся, дівчинонько,
Що йдеш за шофера,
Кождий шофер добре знає,
Де в буфеті двері.

Він по селах всюди їздить,
Кожний його знає,
А куди він не заїде -
Там коханку має.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382277'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382277','Ой, не тішся, дівчинонько','Ой, не тішся, дівчинонько,
Що йдеш за шофера,
Кождий шофер добре знає,
Де в буфеті двері.

Він по селах всюди їздить,
Кожний його знає,
А куди він не заїде -
Там коханку має.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23828','Нестримна течія','Музика: Володимир Івасюк Слова: Богдан Стельмах. Виконує: Тарас Чубай','uk','ukraine_1991',NULL,NULL,'Аудіо-CD: Тарас Чубай та друзі. "Наш Івасюк". 2002','Підбір акордів: bohdanko@pisni.org.ua','Аm               G
В мріях ти була завжди моя,
В мріях я завжди був твій,
Та часу течія, нестримна течія,
Змела сліди тих мрій в душі моїй...

Приспів:
Зникло наше "Бути, чи не бути",
Ген, за гори журавлями одпливло...
І тепер не знаю як забу-ти
Те, чого ніколи не було.

Щирий сміх торкався вуст твоїх,
Щирий сміх, як перший сніг,
Та днів нестримний біг, та днів нестримний біг,
Змести повік не зміг той перший сніг...

Приспів.

В мріях ти була завжди моя,
В мріях я повік був твій,
Та часу течія, нестримна течія,
Лишила давній біль в душі моїй...

Приспів.','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23828','Нестримна течія','Аm               G
