INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382550','Ой, гаю мій зелененький','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, гаю мій зелененький,
Гаю мій, розмаю,
Я у свої мамусеньки
Три розкоші маю:

А першую розкіш маю —
Файно ся убрати,
А другую розкіш маю —
Пускають гуляти.

А третюю розкіш маю —
Мене мама любить,
Щоби-м спала до полудня,
Вона мя не будить.

Ой, казала мені мат
Хату замітати,
А я гиц та й на піч,
Бо я хочу спати!','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382550'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382550','Ой, гаю мій зелененький','Ой, гаю мій зелененький,
Гаю мій, розмаю,
Я у свої мамусеньки
Три розкоші маю:

А першую розкіш маю —
Файно ся убрати,
А другую розкіш маю —
Пускають гуляти.

А третюю розкіш маю —
Мене мама любить,
Щоби-м спала до полудня,
Вона мя не будить.

Ой, казала мені мат
Хату замітати,
А я гиц та й на піч,
Бо я хочу спати!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382573','Ой, у мене добра мамка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, у мене добра мамка:
Жене мя на поле,
А як хочу погуляти —
Не пустить ніколи.

Ой, у тебе добра мати,
Але моя не зла,
Моя мене межи хлопці
Сама би повезла!

Твоя мамка, як малинка,
Моя — як суничка,
Як я не йду межи хлопці,
Каже, що я - дичка.

Коби-м такі очка мала,
Як у тебе, мамко,
Я би-м собі виморґала
Паничика з ґанку.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382573'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382573','Ой, у мене добра мамка','Ой, у мене добра мамка:
