INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382665','Ой, де ідеш, пане-брате?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой де ідеш, пане-брате?
Чи на косовицю?
А на кого зіставляєш
Свою молодицю?

А на тебе зіставляю,
Мій брате Степане,
Доглядай ми молодиці,
З ким вона зістане.

Доглядай ми молодиці,
Доглядай ми жінки,
Як приїду з косовиці,
Куплю ти горілки!','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382665'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382665','Ой, де ідеш, пане-брате?','Ой де ідеш, пане-брате?
Чи на косовицю?
А на кого зіставляєш
Свою молодицю?

А на тебе зіставляю,
Мій брате Степане,
Доглядай ми молодиці,
З ким вона зістане.

Доглядай ми молодиці,
Доглядай ми жінки,
Як приїду з косовиці,
Куплю ти горілки!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2382717','Чому бджоли не йдуть в поле?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Чому бджоли не йдуть в поле?
Чому не рояться?
Чому дівки не гуляють?
Свекрухи бояться.

Ой, свекрухи так, як льохи,
Не хочуть робити,
Тільки ідуть до сусіди
Невістку гудити.

Погадай си, дівчинонько,
В своїй головоньці,
Як то треба догодити
Чужій матіноньці?

У чужої матіноньки
З двома коновками,
Вона мені повідає:
Не рушиш ногами?

Я у свої матіноньки
Дома єдна була,
Я по воду не ходила,
В саду вода була.

Ой, доки я в неньки була
Гуляла, співала,
А як пішла від ненечки,
Все позабувала.

Ой, як пішла до свекрухи,
Стала на порозі,
То забула співаночки
Усі на дорозі.

Як я була в свої мами,
Бренчив голос, бренчив,
Як-єм пішла до свекрухи,
Зараз ми ся зменшив.

Паки-м була коло тата,
То-м була чубата,
А як пішла-м до свекрухи,
З''їли чубок мухи.

А щоби я була знала,
Де є моя свекра,
Була би-м ї затягнула
За ноги до пекла.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2382717'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2382717','Чому бджоли не йдуть в поле?','Чому бджоли не йдуть в поле?
