INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2384354','Пісня першокласника','Музика: Михайло Назарець Слова: Михайло Назарець','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Настя та Софія Коверчуки.','Перший раз іду до школи,
Свій новий портфель несу!
В сонячний день, цей чудовий,
Перший раз до школи йду!

Приспів:
Перший раз у перший клас,
Перший дзвоник, нова школа!
Нових друзів цілий клас,
Перший раз у перший клас!

Мама з татом проводжають
І вітають від душі!
В школі радо зустрічають
Перші мої вчителі!

Приспів.

Перший зошит, перша дошка,
Перший день шкільний у нас!
В цей осінній день чудовий
Ми йдемо у перший клас!

Приспів. (2)

Перший раз у перший клас!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2384354'), datetime('now')),datetime('now'));
