INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2384697','Слава Україні!','Музика: Ольга Монастирська Слова: Ольга Монастирська. Виконує: Ольга Монастирська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Де б у світі не бувала,
І не бачила чого,
Та, напевно, не зрівняти
Краю рідного свого.
Тут поезії Шевченка,
Тут мелодії Чурай,
Тут жива козацька слава,
Ти ж її не забувай!

Приспів:
А я подивлюся в небо синє-синє,
На колосся жовте, на рясні поля
І промовлю: Слава! Слава Україні!
Це моя святиня! Це моя земля!

Жити б де не довелося,
Завжди милий рідний край,
Незабутня щедра осінь,
Срібні зими і розмай.
Як же можна не любити
Землю різної пори,
Де малює барви літо
В синьожовті кольори?..

Приспів.','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2384697'), datetime('now')),datetime('now'));
