INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238756','Стань, Давиде, з гуслями','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Стань, Давиде, з гуслями,
Грай весело враз з нами.
Богу рожденному співаймо,
І всі весело заграймо:
Співаймо і граймо,
Співаймо і граймо,
Днесь у рождестві Його,
Яко Творця нашого прославляймо!
І Ангельські хори всі,
Вся тварь: люди і звірі!
Богу рожденному...
Сонце, місяць і зорі,
Світ з небесних просторів!
Богу рожденному...
Тихі вод і рік плеса
Днесь шумлять під небеса.
Богу рожденному...
Град, огонь і цілий світ
Шлють сьогодні свій привіт.
Богу рожденному...
Гори, ріки, долини,
Луг, діброва, царини!
Богу рожденному...
І князі, і всі царі,
Скоти, гади і звірі!
Богу рожденному...
На тимпанах, сопілках
Гуслях, голосних трубах,
Богу рожденному...
Сотворіння, і всяк цвіт
Вся земля, весь Божий світ!
Богу рожденному','["pisni.org.ua", "cat:cerkovni", "Церковні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238756'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_238756','Стань, Давиде, з гуслями','Стань, Давиде, з гуслями,
