INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238694','Купала на Йвана купавсь Іван та в Воду впав','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Купання. Ягідки. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Купавсь Іван та в Воду впав. Пішли Дівочки по Ягідочки. Були Світилки Яснії Зірки. Всі Дівочки перебрели Дівка Маринка утонула. Не гинь Миленький дам Ти Радоньку. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Купала на Йвана
Купавсь Іван та в Воду впав

Приспів:
Купала на Йвана

На Йвана Купала
Пішли Дівочки по Ягідочки

На Йвана Купала
А Молодиці по Полуниці

На Йвана Купала
Прийшлось Річку брести уплав пливти

На Йвана Купала,
Всі Дівочки перебрели Дівка Маринка утонула    Голос 1','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238694'), datetime('now')),datetime('now'));
