INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238777','А пливала Кладочка під Млином (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Кладочка-Млин. Пара-Непара. Обійми. Друга-Серденько. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. А пливала Кладочка під Млином. Були Світилки Яснії Зірки. Не давала Ганнуся ручки двом. Правой ручкою обняла ще й поцілувала. А я Тебе Другою обійму. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','А пливала Кладочка під Млином
Не давала Ганнуся ручки двом

А на Тобі Нестерку ручку мою
А я Тебе Другою обійму

А я Тебе Другою  обійму
До свойого  Серденька пригорну','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238777'), datetime('now')),datetime('now'));
