INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2388899','Ой, да тихо, тихо Дунай воду несе','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Записано у с.Берлози Чернігівська обл., Козелецький р-н.','Ой, да тихо, тихо
