INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2386022','Давня весна','Музика: Сергій Котовський Слова: Леся Українка','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує виконавиця українського походження Tetiana Maria (https://www.facebook.com/songofukraine/videos/%D0%BF%D1%96%D1%81%D0%BD%D1 %8F-%D0%B4%D0%B0%D0%B2%D0%BD%D1%8F- %D0%B2%D0%B5%D1%81%D0%BD%D0%B0-%D0%BB%D0%B5%D1%81%D1%8F- %D1%83%D0%BA%D1%80%D0%B0%D1%97%D0%BD%D0%BA%D0%B0/1984652458422 004/).','Була весна весела, щедра, мила,
Промінням грала, сипала квітки,
Вона летіла хутко, мов стокрила,
За нею вслід співучії пташки!
Все ожило, усе загомоніло -
Зелений шум, веселая луна!
Співало все, сміялось і бриніло,
А я лежала хвора й самотна...

Приспів:
Весно красна, любі, милі,
Сни мої щасливі,
Я люблю вас, хоч і знаю
Що ви всі зрадливі!..
Весно красна, любі, милі,
Сни мої щасливі,
Я люблю вас!

Я думала: Весна для всіх настала,
Дарунки всім несе вона, ясна,
Для мене тільки дару не придбала,
Мене забула радісна весна...
Ні, не забула! У вікно до мене
Заглянули від яблуні гілки,
Замиготіло листячко зелене,
Посипались білесенькі квітки.

Приспів.

Прилинув вітер і в тісній хатині
Він про весняну волю заспівав,
А з ним прилинули пісні пташині,
І любий гай свій відгук з ним прислав.
Моя душа ніколи не забуде
Того дарунку, що весна дала...
Весни такої не було й не буде,
Як та була, що за вікном цвіла.

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "cat:nostalgia", "Пісні про красу природи", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2386022'), datetime('now')),datetime('now'));
