INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238869','Ой ходила Уляночка по Межі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Межа. Дуб Зелений - Жолуді. Чисте Поле - Роса. Червоні Черевички. Торг. Івасенько-Мати. Вулиця-Вечорниці. Комірочка. Золотий Замок. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. В Чистім Полі Роса впала. А я в Комірочку підкопалася. Пішла на Вулицю нагулялася. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой ходила Уляночка по Межі
Червонії Черевички на нозі

Приспів після кожних двох рядків:
Стій Дубе Зелений
На Дубові Жолуді
В Чистім Полі Роса впала
На Вулиці Купала на Йвана

Червонії Черевички на нозі
Що покупив Івасенько на Торзі
Носи-носи Дівчинонько здорова
А я Тобі не скажу ні слова

Та Петрівочка минаєцця
Сива Зозуля ховаєцця
А чи було Літо чи не було
Чомусь Воно мені не докучило
Що я Молода не гуляла
Що я Челядоньки не видала

Мене Мати не пускала
Тай у Комірочку зачиняла
Тай у Комірочку зачиняла
Золотим Замочком замикала

Золотим Замочком замикала
А замикаючи приговорювала
Отут сиди Доню в Комірочці
Поки розійдуцця Вечорниці

А я в Комірочку підкопалася
Пішла на Вулицю нагулялася','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238869'), datetime('now')),datetime('now'));
