INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2387073','Посміхалися','Музика: Ольга Монастирська Слова: Ольга Монастирська. Виконує: Ольга Монастирська','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Ольга Монастирська.','Затягнуло все та непогодою,
Та непогодою вже тривалий час.
Посміхнутися би не зашкодило,
Би не зашкодило для усіх нас!
Як завадити такому настрою,
Такому настрою, усі знаємо,
Із веселою, гарною піснею,
Такою піснею ми завітаємо!

Приспів.
А ми б хотіли,
Щоб усі ви посміхалися,
І щоб душа відкрилась,
І звучала піснею!
І щоб країною своєю
Милувалися,
Такою гарною, такою різною!
Щоб красувалось наше тіло
Вишиванкою,
І на свята ми зустрічалися
З родиною!
Хай мир і щастя
Прокидається світанками
Над Україною! Над Україною!

Як моторчиком серденько стукає,
А серце стукає, серце стукає!
І мажорними сититься звуками,
А, значить, наше свято настає!
Лиш додайте до буднів фантазії,
Свої фантазії на прийдешній день!
І назавжди покинуть оказії,
І прийде гарний настрій для людей!

Приспів.

Хай мир і щастя
Прокидається світанками
Над Україною! Над Україною!','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2387073'), datetime('now')),datetime('now'));
