INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2390073','Ой, хто, хто Миколая любить?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Чернігівська обл., Ічнянський р-н, с.Бурімка. Записав Леопольд Ященко від Олександри Сенько; пісня з її рідного села; за її пам''яті співалася як колядка на Різдво.','Ой, хто, хто Миколая любить?
Ой хто, хто йому вірно служить?
Приспів:
Чудотворець Миколай,
По всякий час помагай
Цьому дому!
Хазяїн Миколая любить,
Хазяїн йому вірно служить.
Приспів.
І хазяйка Миколая любить,
І хазяйка йому вірно служить.
Приспів.
І їх дітки Миколая люблять,
І їх дітки йому вірно служать.
Приспів.','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2390073'), datetime('now')),datetime('now'));
