INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_238920','Ой що то іде Селом Cелом','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Кінь-Село. Вода-Корж-Душа. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Ой за Горою Річка тече як тая Галя Коржі пече. Ой дай же мені Коржа бо забагає Моя Душа. Були Світилки Яснії Зірки. Будеш Ти Галю Коханкою. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой що то іде Селом-селом
Їхав той Іван Сивим Коньом

Він поганяє Нагайкою
Будеш Ти Галю Коханкою

Ой за Горою Річка тече
Як тая Галя Коржі пече

Ой той Іван Воду носить
А у Галі Коржа просить

Ой Ти Галю Моя Душа
Ой дай мені Коржа-коржа

Ой дай же мені Коржа-коржа
Бо забагає Моя Душа','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_238920'), datetime('now')),datetime('now'));
