INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2391859','Х@й новий рік!','Музика: Роман Строгуш Слова: Роман Строгуш','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує гурт Едельвейс.','Знову настрій святковий,
Білий сніг за вікном,
І вогонь новорічний
Нас зігріє теплом,
Знову всі поспішають
Подарунки знайти,
І разом заспіваймо ми:
Ялинко, гори!

Приспів:
Хай новий рік вам принесе
Любов і здійснення всіх мрій!
У вашім серці хай живе
Тепло із іскрами надій!
Хай буде щастя і добро
У кожнім домі та сім''ї!
Хай мир і злагода живе
На рідній батьківській землі!

Нам постукав вже в двері
Новорічний цей час,
Дід мороз уже в хаті,
Кличем вас всіх до нас!
Подарунків багато
Та ми просим одне:
Хай на всю Україну
Божа ласка зійде!

Приспів.

Хай Новий рік!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2391859'), datetime('now')),datetime('now'));
